def is_subseq(pattern, sequence):
    di = 0
    for pset in pattern:
        found = False
        while di < len(sequence):
            if frozenset(pset) <= frozenset(sequence[di]):
                found = True; di += 1; break
            di += 1
        if not found:
            return False
    return True

def seq_support(pattern, db):
    return sum(1 for s in db.values() if is_subseq(pattern, s))

